/* oms-master-orTypeReason-sql-oracle.xml selectOrTypeReasonDt */ SELECT '0' AS CHK , A.OWKEY , A.ORDERTYPECD , B.ORDERTYPENM , A.ORDERRSNCD , A.ORDERRSNNM , COALESCE(A.DELYN, 'N') AS DELYN , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TORDER_MST_ORTYPEREASON A JOIN TORDER_MST_ORTYPE B ON A.OWKEY = B.OWKEY AND A.ORDERTYPECD = B.ORDERTYPECD WHERE A.OWKEY = #{owkey} AND A.ORDERTYPECD = #{ordertypecd}
AND A.DELYN = #{delyn}
ORDER BY A.ORDERRSNCD, A.UPDATEDATE DESC

SELECT COUNT(1)
  FROM TORDER_MST_ORTYPEREASON
 WHERE OWKEY = #{owkey}
   AND ORDERTYPECD = #{ordertypecd}
   AND ORDERRSNCD = #{orderrsncd}

