	INSERT INTO TORDER_MST_ORTYPEREASON 
	(
	  OWKEY
	, ORDERTYPECD
	, ORDERRSNCD
	, ORDERRSNNM
	, DELYN
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
	)
	VALUES
	(
	  #{owkey}
	, #{ordertypecd}
	, #{orderrsncd}
	, #{orderrsnnm}
    , #{delyn}
    , #{sysdate}
    , #{surkey}
    , #{sysdate}
    , #{surkey}
    )

mapper.update:
/* oms-master-orTypeReason-sql-oracle.xml updateOrTypeReasonDt */
UPDATE TORDER_MST_ORTYPEREASON
   SET ORDERRSNNM = #{orderrsnnm}
     , DELYN = #{delyn}
   	 , UPDATEDATE = #{sysdate}
   	 , UPDATEURKEY = #{surkey}
 WHERE OWKEY = #{owkey}
   AND ORDERTYPECD = #{ordertypecd}
   AND ORDERRSNCD = #{orderrsncd}
